noncompliant:
void function() {
  int unusedVar = 42; // Noncompliant: variable is declared but never used
  int result = calculateSomething();
  printf("Result: %d\n", result);
}

compliant:
void function() {
  int result = calculateSomething(); // Compliant: variable is used
  printf("Result: %d\n", result);
}

// Or if variable must exist for debugging:
void function() {
  [[maybe_unused]] int debugVar = 42; // Compliant: explicitly marked as potentially unused
  int result = calculateSomething();
  printf("Result: %d\n", result);
}
